const geo = $input.first().json[0];
const prev = $('Code - Préparer dates').first().json;

if (!geo) throw new Error('Adresse introuvable : ' + prev.adresse);

return [{
  json: {
    ...prev,
    lat: parseFloat(geo.lat),
    lng: parseFloat(geo.lon),
  }
}];

const { lat, lng, duree, jours } = $('Code - Extraire coordonnées').first().json;
const allDeals = $input.first().json.results || [];

// Coordonnées approximatives du point de départ (dépôt / domicile) de chaque technicien
const techHomes = {
  tech1: { lat: 50.6, lng: 3.0 },
  tech2: { lat: 50.5, lng: 3.0 },
};

const MAX_JOBS_PAR_JOUR = 5;

// Distance vol d'oiseau en km (approximation rapide)
function distKm(lat1, lng1, lat2, lng2) {
  const R = 6371;
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLng = (lng2 - lng1) * Math.PI / 180;
  const a = Math.sin(dLat/2)**2 +
    Math.cos(lat1 * Math.PI/180) *
    Math.cos(lat2 * Math.PI/180) *
    Math.sin(dLng/2)**2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
}

const scores = [];

for (const jour of jours) {
  for (const [techId, home] of Object.entries(techHomes)) {

    // Jobs déjà planifiés ce jour pour ce tech
    const jobsDuJour = allDeals.filter(d =>
      d.properties.rdv_date?.startsWith(jour) &&
      d.properties.technicien_assigne === techId
    );

    if (jobsDuJour.length >= MAX_JOBS_PAR_JOUR) continue;

    // Distance moyenne du nouveau job aux jobs existants
    let distScore = 0;
    if (jobsDuJour.length === 0) {
      // Jour vide : distance depuis le domicile du tech
      distScore = distKm(home.lat, home.lng, lat, lng);
    } else {
      // Distance moyenne aux jobs existants
      const dists = jobsDuJour.map(j =>
        distKm(
          parseFloat(j.properties.rdv_lat),
          parseFloat(j.properties.rdv_lng),
          lat, lng
        )
      );
      distScore = dists.reduce((a, b) => a + b, 0) / dists.length;
    }

    // Score final : distance (km) + pénalité charge (jobs existants × 5km équivalent)
    const chargeScore = jobsDuJour.length * 5;
    const totalScore = distScore + chargeScore;

    scores.push({
      jour,
      techId,
      nbJobsExistants: jobsDuJour.length,
      distKm: Math.round(distScore * 10) / 10,
      score: Math.round(totalScore * 10) / 10,
    });
  }
}

// Trier par score croissant, garder les 3 meilleurs
const top3 = scores
  .sort((a, b) => a.score - b.score)
  .slice(0, 3);

return top3.map(s => ({ json: s }));

const slots = $input.all().map(i => i.json);
const { adresse, lat, lng, duree } = $('Code - Extraire coordonnées').first().json;

const techLabels = {
  tech1: 'Technicien 1',
  tech2: 'Technicien 2',
};

const formatted = slots.map((s, i) => {
  const date = new Date(s.jour);
  const label = date.toLocaleDateString('fr-FR', {
    weekday: 'long', day: 'numeric', month: 'long'
  });
  return {
    rang: i + 1,
    jour: s.jour,
    jour_label: label,
    technicien: s.techId,
    technicien_label: techLabels[s.techId],
    interventions_existantes: s.nbJobsExistants,
    distance_moyenne_km: s.distKm,
  };
});

return [{
  json: {
    adresse,
    lat,
    lng,
    duree,
    slots: formatted,
    // Pour Léa : phrase lisible
    reponse_lea: formatted.map(s =>
      `Option ${s.rang} : ${s.jour_label} avec le ${s.technicien_label} ` +
      `(${s.interventions_existantes} intervention(s) déjà prévue(s) ce jour-là)`
    ).join(' | ')
  }
}];

const { adresse, duree, jours_a_scanner } = $input.first().json;

// Générer les N prochains jours ouvrés
const jours = [];
const today = new Date();

for (let i = 1; jours.length < (jours_a_scanner || 14); i++) {
  const d = new Date(today);
  d.setDate(today.getDate() + i);
  const dow = d.getDay();
  if (dow !== 0 && dow !== 6) { // exclure week-ends
    jours.push(d.toISOString().split('T')[0]); // YYYY-MM-DD
  }
}

return [{ json: { adresse, duree: duree || 60, jours } }];
